import{c as r,Q as e,j as o,m as t}from"./chunks/framework.BXc4yaFE.js";const p=JSON.parse('{"title":"How the Creator of Claude Code Actually Uses It","description":"","frontmatter":{"url":"https://mindwiredai.com/2026/03/25/claude-code-creator-workflow-claudemd/","title":"How the Creator of Claude Code Actually Uses It","type":"article"},"headers":[],"relativePath":"research/ai-articles/11-mindwiredai-boris-creator-workflow.md","filePath":"research/ai-articles/11-mindwiredai-boris-creator-workflow.md","lastUpdated":1779894392000}'),l={name:"research/ai-articles/11-mindwiredai-boris-creator-workflow.md"};function i(s,a,d,n,c,h){return e(),o("div",null,[...a[0]||(a[0]=[t('<h1 id="how-the-creator-of-claude-code-actually-uses-it" tabindex="-1">How the Creator of Claude Code Actually Uses It <a class="header-anchor" href="#how-the-creator-of-claude-code-actually-uses-it" aria-label="Permalink to &quot;How the Creator of Claude Code Actually Uses It&quot;">​</a></h1><p><strong>原始 URL</strong>: <a href="https://mindwiredai.com/2026/03/25/claude-code-creator-workflow-claudemd/" target="_blank" rel="noreferrer">https://mindwiredai.com/2026/03/25/claude-code-creator-workflow-claudemd/</a></p><p><strong>作者</strong>: roro_ai<br><strong>發佈日期</strong>: 2026 年 3 月 25 日<br><strong>來源</strong>: MindWired AI</p><hr><h2 id="核心摘要" tabindex="-1">核心摘要 <a class="header-anchor" href="#核心摘要" aria-label="Permalink to &quot;核心摘要&quot;">​</a></h2><p>本文介紹了 Claude Code 創造者、Anthropic 員工工程師 Boris Cherny 在 2026 年 1 月公開分享的開發工作流程與配置實踐。他的方法核心圍繞著一份簡潔的 CLAUDE.md 檔案（約 100 行），概述了系統化的 AI 輔助編碼最佳實踐。</p><h3 id="核心哲學" tabindex="-1">核心哲學 <a class="header-anchor" href="#核心哲學" aria-label="Permalink to &quot;核心哲學&quot;">​</a></h3><p>Cherny 強調「幾乎所有最佳實踐都歸結為一件事：上下文視窗管理」。他優先考慮簡潔性、消除不必要的指令，以及圍繞 AI 建立系統，而不是微管理它。</p><h3 id="三大核心原則" tabindex="-1">三大核心原則 <a class="header-anchor" href="#三大核心原則" aria-label="Permalink to &quot;三大核心原則&quot;">​</a></h3><ol><li><strong>簡潔優先</strong> — 最小化、聚焦的變更</li><li><strong>不懶惰</strong> — 解決根本原因，避免臨時修補</li><li><strong>最小影響</strong> — 僅修改必要部分</li></ol><h3 id="任務管理迴圈" tabindex="-1">任務管理迴圈 <a class="header-anchor" href="#任務管理迴圈" aria-label="Permalink to &quot;任務管理迴圈&quot;">​</a></h3><p>計畫 → 驗證 → 追蹤 → 解釋 → 文件化 → 通過 CLAUDE.md 更新捕獲教訓</p><hr><h2 id="關鍵實踐" tabindex="-1">關鍵實踐 <a class="header-anchor" href="#關鍵實踐" aria-label="Permalink to &quot;關鍵實踐&quot;">​</a></h2><p><strong>並行執行與效率</strong></p><ul><li>每日同時運行 10-15 個 Claude 會話，使用獨立的 git worktrees</li><li>運用「計畫模式」進行複雜任務，先迭代確認策略再執行</li><li>慷慨使用 subagents 保持乾淨的上下文視窗</li><li>應用「不要陪護」(Don&#39;t babysit) 原則</li></ul><p><strong>文件與學習</strong></p><ul><li>將 CLAUDE.md 視為活文件，在出現錯誤時更新</li><li>記錄教訓與模式，形成可重複的決策框架</li><li>團隊知識累積優於個人知識</li></ul><hr><h2 id="關鍵引用與數據" tabindex="-1">關鍵引用與數據 <a class="header-anchor" href="#關鍵引用與數據" aria-label="Permalink to &quot;關鍵引用與數據&quot;">​</a></h2><blockquote><p>「幾乎所有最佳實踐都歸結為一件事：上下文視窗管理。」— Boris Cherny</p></blockquote><p><strong>並行執行規模</strong>: 10-15 個同時 Claude 會話，經由分離的 git worktrees 隔離<br><strong>CLAUDE.md 大小</strong>: 約 100 行，作為系統化方法的核心檔案</p><p>此方法論適用於編碼以外的 AI 協作場景，展示了縱向擴展人類-AI 協作的可能性。</p><hr><h2 id="工作流程適用性" tabindex="-1">工作流程適用性 <a class="header-anchor" href="#工作流程適用性" aria-label="Permalink to &quot;工作流程適用性&quot;">​</a></h2><p>該方法論強調長期系統建設而非個別會話最佳化，透過文件化與知識累積實現團隊層級的 AI 效能提升。</p>',26)])])}const m=r(l,[["render",i]]);export{p as __pageData,m as default};
